member.summary:
Stable machine-readable error code. Never renamed once shipped;
deprecated codes are dual-written for 6 months alongside
replacements.

example.code:
var isa = await Isa.WithLicenseAsync(new LicenseOptions
{
    Keycode = "ABC-123-XYZ",
    Email   = "agent@example.com",
});

var isa = Isa.WithSession(new SessionOptions { SessionId = "sess_…", SessionSecret = "…" });
var body = await isa.Proxy.CallAsync(new ProxyCallOptions
{
    IntegrationUuid = "int_abc",
    Params = new { foo = "bar" },
});

var iter = isa.Zyins.Cases.List(new ListOptions());
await foreach (var c in iter)
{
    await Process(c);
    if (ShouldStop())
    {
        await checkpoint.SaveAsync(iter.Cursor);
        return;
    }
}

// later, in a new process:
var resumed = isa.Zyins.Cases.List(new ListOptions { Cursor = await checkpoint.LoadAsync() });
await foreach (var c in resumed) { /* ... */ }

var page = await Pagination.FirstPageAsync(fetcher, new ListOptions());
foreach (var row in page.Data) { /* ... */ }
// page.NextCursor is null on the last page.

var result = await isa.Prequalify.RunAsync(new PrequalifyInput
{
    Applicant = new Applicant
    {
        Name         = "John Doe",
        Dob          = "1962-04-18",
        Sex          = Sex.Male,
        State        = "NC",
        HeightInches = 70,
        WeightLbs    = 195,
        NicotineUse  = NicotineUsage.None,
    },
    Coverage   = Coverage.FaceValue(25_000),
    Products   = new[] { "senior-life" },
});

var isa = Isa.WithLicense(new LicenseCredentials
{
    Keycode = "ABC-123-XYZ",
    Email   = "agent@example.com",
});
